#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Seg{
    int xu,xd,y,d;
}seg[2*N];

struct Node{
    int tag,len;
}t[8*N];

int n,b[2*N],m;
long long ans;
map<int,int> id;

bool cmp(Seg x,Seg y){
    return x.y<y.y;
}

int cal(Node t,int l,int r){
    if(l==r)
        return (t.tag>0)*(b[r+1]-b[l]);
    else
        return max((t.tag>0)*(b[r+1]-b[l]),t.len);
}

void modify(int cur,int l,int r,int x,int y,int k){
    if(x<=l && r<=y){
        t[cur].tag+=k;
        return;
    }
    t[cur*2].tag+=t[cur].tag;
    t[cur*2+1].tag+=t[cur].tag;
    t[cur].tag=0;
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k);
    t[cur].tag=min(t[cur*2].tag,t[cur*2+1].tag);
    t[cur*2].tag-=t[cur].tag,t[cur*2+1].tag-=t[cur].tag;
    t[cur].len=cal(t[cur*2],l,mid)+cal(t[cur*2+1],mid+1,r);
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d%d%d",&seg[2*i].xu,&seg[2*i-1].y,&seg[2*i].xd,&seg[2*i].y);
        seg[2*i-1].xu=seg[2*i].xu,seg[2*i-1].xd=seg[2*i].xd;
        seg[2*i-1].d=1,seg[2*i].d=-1;
        b[2*i]=seg[2*i].xu,b[2*i-1]=seg[2*i].xd;
    }
    sort(b+1,b+2*n+1);
    m=unique(b+1,b+2*n+1)-b-1;
    for(int i=1;i<=m;i++)
        id[b[i]]=i;
    sort(seg+1,seg+2*n+1,cmp);
    for(int i=1;i<=2*n;i++){
        /*
        printf("%d %d %d %d\n",id[seg[i].xu],id[seg[i].xd]-1,seg[i].y,seg[i].d);
        printf("%lld\n",1LL*cal(t[1],1,m-1));
        for(int j=1;j<8;j++)
            printf("%d %d\n",t[j].tag,t[j].len);
        */
        if(i>1)
            ans+=1LL*cal(t[1],1,m-1)*(seg[i].y-seg[i-1].y);
        modify(1,1,m-1,id[seg[i].xu],id[seg[i].xd]-1,seg[i].d);
    }
    printf("%lld",ans);
    return 0;
}
